      "content": "const { randomUUID } = require('node:crypto');
const { sendError } = require('../lib/errors');

const comments = [];

const createComment = async (projectId, taskId, comment) => {
  const newComment = { id: randomUUID(), projectId, taskId, ...comment };
  comments.push(newComment);
  return newComment;
};

const addComment = async (projectId, taskId, message) => {
  const normalizedMessage = String(message || '').trim();
  if (!normalizedMessage) {
    throw sendError(400, 'BAD_REQUEST', 'Comment message is required');
  }
  const payload = { message: normalizedMessage };
  return await createComment(projectId, taskId, payload);
};

const getAllComments = async (projectId, taskId) => {
  const projectKey = String(projectId || '');
  const taskKey = String(taskId || '');
  const list = Array.isArray(comments) ? comments : [];
  return list.filter(comment => comment && String(comment.projectId || '') === projectKey && String(comment.taskId || '') === taskKey);
};

module.exports = { createComment, addComment, getAllComments };
