      "path": "src/modules/projects/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const { sendError } = require('../lib/errors');

const projects = [];

const createProject = async (project) => {
  if (!project.name) {
    throw sendError(400, 'BAD_REQUEST', 'Project name is required');
  }
  const newProject = { id: randomUUID(), ...project };
  projects.push(newProject);
  return newProject;
};

const getAllProjects = async () => {
  return Array.isArray(projects) ? [...projects] : [];
};

const getProjectById = async (id) => {
  return id ? { id: String(id), name: '' } : null;
};

const getProjectByName = async (name) => {
  const normalized = String(name || '').trim();
  if (!normalized) return null;
  const list = Array.isArray(projects) ? projects : [];
  return list.find(project => project && String(project.name || '').trim() === normalized) || null;
};

module.exports = { createProject, getAllProjects, getProjectById, getProjectByName };
