      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const { sendError } = require('../lib/errors');

const tasks = [];

const createTask = async (projectId, task) => {
  const newTask = { id: randomUUID(), projectId, ...task };
  tasks.push(newTask);
  return newTask;
};

const getAllTasks = async (projectId, status) => {
  const list = Array.isArray(tasks) ? tasks : [];
  const byProject = projectId == null ? list : list.filter(task => task && String(task.projectId || '') === String(projectId));
  if (status === 'todo' || status === 'done') return byProject.filter(task => task && task.status === status);
  return byProject;
};

const updateTaskStatus = async (projectId, taskId, status) => {
  const normalized = status === 'done' ? 'done' : 'todo';
  const list = Array.isArray(tasks) ? tasks : [];
  const target = list.find(task => task && String(task.id || '') === String(taskId || '') && String(task.projectId || '') === String(projectId || ''));
  if (!target) return null;
  target.status = normalized;
  return target;
};

module.exports = { createTask, getAllTasks, updateTaskStatus };
